		assertProjectData("bundles/foo.bar.bundle-2", projectData, //
				"foo.bar:foo.bar.bundle-2:1.0.0:eclipse-plugin", "Bundle 2 from pom.xml", "bundle2-from-pomXML");

		assertProjectData("bundles-2/foo.bar.bundle-5", projectData, //
